# Zod Schema Definitions

Schemas are the foundation of Zod. Every schema is a validator that checks input data and infers a TypeScript type.

## Primitives

```typescript
import { z } from "zod";

z.string()     // string
z.number()     // number
z.boolean()    // boolean
z.date()       // Date
z.bigint()     // bigint
z.symbol()     // symbol
z.undefined()  // undefined
z.null()       // null
z.void()       // void (undefined)
z.any()        // any — disables type checking
z.unknown()    // unknown — type-safe any
z.never()      // never — always fails
z.nan()        // NaN
```

## Objects

```typescript
const UserSchema = z.object({
  id: z.string().uuid(),
  name: z.string().min(1).max(100),
  email: z.string().email(),
  age: z.number().int().positive().optional(),
  role: z.enum(["admin", "user", "guest"]),
  metadata: z.record(z.string(), z.unknown()).optional(),
});

// Access the shape
UserSchema.shape.name; // z.ZodString
UserSchema.keyof(); // z.ZodEnum<["id", "name", "email", "age", "role", "metadata"]>

// Extend with additional fields
const AdminSchema = UserSchema.extend({
  permissions: z.array(z.string()),
  department: z.string(),
});

// Merge two schemas
const merged = SchemaA.merge(SchemaB);

// Pick / Omit specific fields
const LoginSchema = UserSchema.pick({ email: true });
const PublicUser = UserSchema.omit({ email: true, metadata: true });

// Make all fields optional / required
const PartialUser = UserSchema.partial(); // all optional
const RequiredUser = PartialUser.required(); // all required back
const PartialExcept = UserSchema.partial({ age: true, metadata: true }); // selective
```

## Object Parsing Modes

```typescript
// Strip unknown keys (default)
UserSchema.parse({ name: "Alice", extra: true });
// { name: "Alice" } — extra is stripped

// Passthrough unknown keys
const Loose = UserSchema.passthrough();
Loose.parse({ name: "Alice", extra: true });
// { name: "Alice", extra: true }

// Reject unknown keys
const Strict = UserSchema.strict();
Strict.parse({ name: "Alice", extra: true });
// throws ZodError — unrecognized key "extra"

// Catchall for unknown keys
const WithCatchall = UserSchema.catchall(z.string());
```

## Arrays

```typescript
const StringArray = z.array(z.string());
// or equivalently:
const StringArray2 = z.string().array();

// Constraints
z.array(z.number()).nonempty();  // at least 1 element
z.array(z.number()).min(2);      // at least 2 elements
z.array(z.number()).max(10);     // at most 10 elements
z.array(z.number()).length(5);   // exactly 5 elements

// Access element schema
StringArray.element; // z.ZodString
```

## Tuples

```typescript
// Fixed-length typed arrays
const Point = z.tuple([z.number(), z.number()]);
type Point = z.infer<typeof Point>; // [number, number]

const NameAge = z.tuple([z.string(), z.number()]);
NameAge.parse(["Alice", 30]); // ✓

// Variadic tuples with rest
const AtLeastOne = z.tuple([z.string()]).rest(z.string());
type AtLeastOne = z.infer<typeof AtLeastOne>; // [string, ...string[]]
```

## Enums

```typescript
// Zod enums — string literals
const RoleEnum = z.enum(["admin", "user", "guest"]);
type Role = z.infer<typeof RoleEnum>; // "admin" | "user" | "guest"

RoleEnum.enum.admin; // "admin" — autocomplete-friendly access
RoleEnum.options;     // ["admin", "user", "guest"]

// Native TypeScript enums
enum Direction { North, South, East, West }
const DirectionSchema = z.nativeEnum(Direction);

// Const objects as enums
const STATUS = { Active: "active", Inactive: "inactive" } as const;
const StatusSchema = z.nativeEnum(STATUS);
```

## Unions and Intersections

```typescript
// Union — value matches any one schema
const StringOrNumber = z.union([z.string(), z.number()]);
// or: z.string().or(z.number())

// Discriminated union — tagged union with a shared discriminant key
const EventSchema = z.discriminatedUnion("type", [
  z.object({ type: z.literal("click"), x: z.number(), y: z.number() }),
  z.object({ type: z.literal("keypress"), key: z.string() }),
  z.object({ type: z.literal("scroll"), delta: z.number() }),
]);
// Much better error messages than plain union — Zod checks the discriminant first

// Intersection — value must match both schemas
const NameAndAge = z.intersection(
  z.object({ name: z.string() }),
  z.object({ age: z.number() }),
);
// or: z.object({ name: z.string() }).and(z.object({ age: z.number() }))
```

## Records and Maps

```typescript
// Record — string-keyed dictionary
const StringRecord = z.record(z.string()); // Record<string, string>
const TypedRecord = z.record(z.string(), z.number()); // Record<string, number>

// Map
const UserMap = z.map(z.string(), UserSchema); // Map<string, User>

// Set
const UniqueIds = z.set(z.string()); // Set<string>
z.set(z.number()).nonempty(); // non-empty set
z.set(z.number()).min(2).max(10); // size constraints
```

## Literals and Special Types

```typescript
// Literal — exact value
const Tuna = z.literal("tuna");
const FortyTwo = z.literal(42);
const True = z.literal(true);

// Lazy — recursive schemas
interface Category {
  name: string;
  subcategories: Category[];
}
const CategorySchema: z.ZodType<Category> = z.object({
  name: z.string(),
  subcategories: z.lazy(() => CategorySchema.array()),
});

// Promise
const PromisedString = z.promise(z.string());
// validates that input is a Promise, and .then() result matches z.string()

// Function
const FnSchema = z.function()
  .args(z.string(), z.number())
  .returns(z.boolean());
// (arg0: string, arg1: number) => boolean
```

## Environment Variables

No environment variables required. Zod is a pure runtime library.
